<template>
  <div>
    <template v-if="$route.path.indexOf('detail') === -1">
      <el-table
        v-loading="loading"
        border
        :data="giveLogList"
        :height="wheight - 90"
      >
        <el-table-column
          width="180"
          label="發放時間"
        >
          <template slot-scope="scope">
            <i class="el-icon-time" /> {{ scope.row.created | datetime('YYYY-MM-DD HH:mm:ss') }}
          </template>
        </el-table-column>
        <el-table-column
          prop="sender"
          label="操作員"
        >
          <template slot-scope="scope">
            <i class="el-icon-user" /> {{ scope.row.sender }}
          </template>
        </el-table-column>
        <el-table-column
          prop="number"
          width="80"
          label="贈送數量"
        />
        <el-table-column
          prop="error"
          width="80"
          label="失敗數量"
        />
        <el-table-column
          width="140"
          label="操作"
        >
          <template slot-scope="scope">
            <router-link
              :to="{ path: matchHidePage('detail/') + scope.row.give_id }"
            >
              發送失敗詳情
            </router-link>
          </template>
        </el-table-column>
      </el-table>
      <div class="content-padded content-center">
        <el-pagination
          layout="prev, pager, next"
          :current-page.sync="params.page"
          :total="totalCount"
          :page-size="params.pageSize"
          @current-change="handleCurrentChange"
        />
      </div>
    </template>
    <router-view />
  </div>
</template>

<script>
import { mapGetters } from 'vuex'
import { getGiveLogList } from '../../../api/promotions'
export default {
  data () {
    return {
      loading: false,
      giveLogList: [],
      totalCount: 0,
      params: {
        page: 1,
        pageSize: 20
      }
    }
  },
  computed: {
    ...mapGetters(['wheight'])
  },
  mounted () {
    this.getGiveLogList()
  },
  methods: {
    handleCurrentChange (pageNum) {
      this.params.page = pageNum
      this.getGiveLogList()
    },
    getGiveLogList () {
      this.loading = true
      getGiveLogList(this.params)
        .then((response) => {
          this.giveLogList = response.data.data.list
          this.totalCount = response.data.data.total_count
          this.loading = false
        })
        .catch((error) => {
          this.loading = false
          this.$message({
            type: 'error',
            message: '獲取優惠券發放列表信息出錯'
          })
        })
    }
  }
}
</script>
